{
  "mode": "method",
  "tests": [
    {
      "name": "basic_infusion",
      "input": ["track1.mp3", 30],
      "output": {"intensity": 30, "has_frequencies": true},
      "notes": "Tests basic functionality with a standard track and a moderate intensity."
    },
    {
      "name": "high_intensity_infusion",
      "input": ["track2.mp3", 80],
      "output": {"intensity": 80, "has_frequencies": true},
      "notes": "Tests the algorithm's ability to handle high intensity without altering listenability."
    },
    {
      "name": "low_intensity_infusion",
      "input": ["track3.mp3", 5],
      "output": {"intensity": 5, "has_frequencies": true},
      "notes": "Tests the minimum intensity level to ensure frequencies are still embedded."
    },
    {
      "name": "no_infusion",
      "input": ["track4.mp3", 0],
      "output": {"intensity": 0, "has_frequencies": false},
      "notes": "Edge case to ensure no frequencies are added when intensity is zero."
    },
    {
      "name": "silent_track",
      "input": ["silent.mp3", 50],
      "output": {"intensity": 50, "has_frequencies": false},
      "notes": "Tests behavior with a silent track to ensure no frequencies can be added."
    },
    {
      "name": "long_track",
      "input": ["long_track.mp3", 40],
      "output": {"intensity": 40, "has_frequencies": true},
      "notes": "Tests performance and functionality with a longer audio track."
    },
    {
      "name": "short_track",
      "input": ["short_track.mp3", 20],
      "output": {"intensity": 20, "has_frequencies": true},
      "notes": "Tests performance with a very short audio track."
    },
    {
      "name": "non_audio_file",
      "input": ["image.png", 50],
      "output": {"error": "Invalid file type"},
      "notes": "Edge case to ensure the algorithm handles non-audio files gracefully."
    }
  ],
  "assumptions": "Tracks are in MP3 format and accessible. Intensity is a percentage from 0 to 100.",
  "notes": "Ensure that the output format is consistent with the expected structure."
}
